function checkForPrimes(numbers) {
    // Helper function to check if a number is prime
    function isPrime(num) {
        if (num <= 1) return false; // 0 and 1 are not prime numbers
        if (num <= 3) return true; // 2 and 3 are prime numbers
        if (num % 2 === 0 || num % 3 === 0) return false; // Eliminate multiples of 2 and 3

        for (let i = 5; i * i <= num; i += 6) {
            if (num % i === 0 || num % (i + 2) === 0) return false; // Check for factors
        }
        return true; // If no factors found, num is prime
    }

    // Iterate through the input array and check for prime numbers
    for (const number of numbers) {
        if (isPrime(number)) {
            console.log(number); // Print the prime number
        }
    }
}

// Example usage:
