```cpp
#include <string>
#include <sstream>
#include <vector>
#include <cctype>

std::string markdownToHtml(const std::string& markdown) {
    std::stringstream html;
    std::vector<std::string> lines = split(markdown, '\n');

    bool inList = false;
    for (const auto& line : lines) {
        if (line.empty()) {
            html << "<p></p>"; // Empty paragraph
            continue;
        }

        // Handle headings
        if (line[0] == '#') {
            int level = 1;
            while (level < 6 && line[level] == '#') {
                ++level;
            }
            html << "<h" << level << ">" << line.substr(level + 1) << "</h" << level << ">";
            continue;
        }

        // Handle bold and italic text
        std::string text = line;
        size_t pos = 0;
        while ((pos = text.find("**")) != std::string::npos) {
            html << text.substr(0, pos);
            text = text.substr(pos + 2);
            pos = text.find("**");
            if (pos != std::string::npos) {
                html << "<strong>" << text.substr(0, pos) << "</strong>";
                text = text.substr(pos + 2);
            }
        }
        while ((pos = text.find("*")) != std::string::npos) {
            html << text.substr(0, pos);
            text = text.substr(pos + 1);
            pos = text.find("*");
            if (pos != std::string::npos) {
                html << "<em>" << text.substr(0, pos) << "</em>";
                text = text.substr(pos + 1);
            }
        }
        html << text;

        // Handle unordered lists
        if (line[0] == '-') {
            if (!inList) {
                html << "<ul>";
                inList = true;
            }
            html << "<li>" << line.substr(2) << "</li>";
        } else {
            if (inList) {
                html << "</ul>";
                inList = false;
            }
            html << "<p>" << line << "</p>";
        }
    }

    if (inList) {
        html << "</ul>";
    }

    return html.str();
}

std::vector<std::string> split(const std::string& str, char delimiter) {
    std::vector<std::string> tokens;
    std::string token;
    std::istringstream tokenStream(str);
    while (std::getline(tokenStream, token, delimiter)) {
        tokens.push_back(token);
    }
    return tokens;
}
```

### Explanation:
1. **Splitting the Input**: The `split` function breaks the input Markdown string into lines.
2. **Processing Each Line**:
   - **Headings**: If a line starts with `#`, it's treated as a heading. The number of `#` characters determines the heading level (h1 to h6).
   - **Bold and Italic Text**: The function looks for `**` and `*` to wrap text in `<strong>` and `<em>` tags, respectively.
   - **Unordered Lists**: If a line starts with `-`, it's treated as a list item. The function keeps track of whether it's currently in a list to properly open and close `<ul>` tags.
3. **Output**: The processed HTML is accumulated in a `std::stringstream` and returned as a string.

### Usage Example:
```cpp
int main() {
    std::string markdown = "# Heading\n\nThis is **bold** and *italic* text.\n\n- Item 1\n- Item 2";
    std::string html = markdownToHtml(markdown);
    std::cout << html << std::endl;
    return 0;
}
```

### Note:
This implementation is quite basic and may not cover all edge cases or advanced Markdown features. You may want to enhance it further based on your specific requirements or use a dedicated Markdown parsing library for more comprehensive support.

