Here's a simplified example of how you might structure your code using SDL. This example assumes you have basic knowledge of C and SDL.

### Prerequisites

1. **Install SDL**: Make sure you have SDL2 installed on your system. You can download it from [libsdl.org](https://www.libsdl.org/download-2.0.php).

2. **Setup Your Project**: Create a new C project and link against the SDL2 library.

### Example Code

Here's a simplified version of the Snake game using SDL:

```c
#include <SDL.h>
#include <stdbool.h>
#include <stdio.h>
#include <stdlib.h>
#include <time.h>

#define SCREEN_WIDTH 640
#define SCREEN_HEIGHT 480
#define GRID_SIZE 20
#define SNAKE_LENGTH 5

typedef struct {
    int x, y;
} Point;

typedef struct {
    Point points[SNAKE_LENGTH];
    int length;
    int direction; // 0: up, 1: down, 2: left, 3: right
} Snake;

typedef struct {
    Point position;
} Food;

// Function prototypes
void initSDL();
void loadImages(SDL_Texture **textures, SDL_Renderer *renderer);
void drawGrid(SDL_Renderer *renderer);
void drawSnake(SDL_Renderer *renderer, SDL_Texture *snakeTexture, Snake *snake);
void drawFood(SDL_Renderer *renderer, SDL_Texture *foodTexture, Food *food);
void updateSnake(Snake *snake, Food *food);
void handleEvents(SDL_Event *event, Snake *snake);
void cleanup(SDL_Renderer *renderer, SDL_Texture *snakeTexture, SDL_Texture *foodTexture);

int main() {
    srand(time(NULL)); // Seed for random number generation

    SDL_Init(SDL_INIT_VIDEO);
    SDL_Window *window = SDL_CreateWindow("Snake Game", SDL_WINDOWPOS_CENTERED, SDL_WINDOWPOS_CENTERED, SCREEN_WIDTH, SCREEN_HEIGHT, 0);
    SDL_Renderer *renderer = SDL_CreateRenderer(window, -1, SDL_RENDERER_ACCELERATED);

    SDL_Texture *snakeTexture, *foodTexture;
    loadImages(&snakeTexture, &foodTexture, renderer);

    Snake snake = {{ {0, 0} }, SNAKE_LENGTH, 2}; // Initial position and direction
    Food food = { {rand() % (SCREEN_WIDTH / GRID_SIZE), rand() % (SCREEN_HEIGHT / GRID_SIZE)} };

    bool running = true;
    SDL_Event event;

    while (running) {
        while (SDL_PollEvent(&event)) {
            handleEvents(&event, &snake);
            if (event.type == SDL_QUIT) {
                running = false;
            }
        }

        updateSnake(&snake, &food);
        if (snake.points[0].x == food.position.x && snake.points[0].y == food.position.y) {
            // Snake eats food, grow and generate new food
            snake.length++;
            food.position.x = rand() % (SCREEN_WIDTH / GRID_SIZE);
            food.position.y = rand() % (SCREEN_HEIGHT / GRID_SIZE);
        }

        SDL_SetRenderDrawColor(renderer, 0, 0, 0, 255);
        SDL_RenderClear(renderer);
        drawGrid(renderer);
        drawSnake(renderer, snakeTexture, &snake);
        drawFood(renderer, foodTexture, &food);
        SDL_RenderPresent(renderer);
    }

    cleanup(renderer, snakeTexture, foodTexture);
    SDL_DestroyWindow(window);
    SDL_Quit();

    return 0;
}

void initSDL() {
    if (SDL_Init(SDL_INIT_VIDEO) < 0) {
        printf("SDL could not initialize! SDL Error: %s\n", SDL_GetError());
        exit(1);
    }
}

void loadImages(SDL_Texture **textures, SDL_Renderer *renderer) {
    // Load your images here
    // Example: textures[0] = IMG_LoadTexture(renderer, "snake.png");
    // Example: textures[1] = IMG_LoadTexture(renderer, "food.png");
}

void drawGrid(SDL_Renderer *renderer) {
    // Draw grid lines
    for (int i = 0; i < SCREEN_WIDTH; i += GRID_SIZE) {
        SDL_RenderDrawLine(renderer, i, 0, i, SCREEN_HEIGHT);
    }
    for (int i = 0; i < SCREEN_HEIGHT; i += GRID_SIZE) {
        SDL_RenderDrawLine(renderer, 0, i, SCREEN_WIDTH, i);
    }
}

void drawSnake(SDL_Renderer *renderer, SDL_Texture *snakeTexture, Snake *snake) {
    for (int i = 0; i < snake->length; i++) {
        SDL_Rect rect = { snake->points[i].x * GRID_SIZE, snake->points[i].y * GRID_SIZE, GRID_SIZE, GRID_SIZE };
        SDL_RenderCopy(renderer, snakeTexture, NULL, &rect);
    }
}

void drawFood(SDL_Renderer *renderer, SDL_Texture *foodTexture, Food *food) {
    SDL_Rect rect = { food->position.x * GRID_SIZE, food->position.y * GRID_SIZE, GRID_SIZE, GRID_SIZE };
    SDL_RenderCopy(renderer, foodTexture, NULL, &rect);
}

void updateSnake(Snake *snake, Food *food) {
    // Update snake position based on direction
    for (int i = snake->length - 1; i > 0; i--) {
        snake->points[i] = snake->points[i - 1];
    }
    switch (snake->direction) {
        case 0: snake->points[0].y--; break;
        case 1: snake->points[0].y++; break;
        case 2: snake->points[0].x--; break;
        case 3: snake->points[0].x++; break;
    }
}

void handleEvents(SDL_Event *event, Snake *snake) {
    if (event->type == SDL_KEYDOWN) {
        switch (event->key.keysym.sym) {
            case SDLK_UP: if (snake->direction != 1) snake->direction = 0; break;
            case SDLK_DOWN: if (snake->direction != 0) snake->direction = 1; break;
            case SDLK_LEFT: if (snake->direction != 3) snake->direction = 2; break;
            case SDLK_RIGHT: if (snake->direction != 2) snake->direction = 3; break;
        }
    }
}

void cleanup(SDL_Renderer *renderer, SDL_Texture *snakeTexture, SDL_Texture *foodTexture) {
    SDL_DestroyTexture(snakeTexture);
    SDL_DestroyTexture(foodTexture);
    SDL_DestroyRenderer(renderer);
}
```

